// === INTERFACES ENTERPRISE OTIMIZADAS ===
interface OptimizationOption {
  id: string;
  title: string;
  description: string;
  category: 'layout' | 'placement' | 'format' | 'targeting' | 'advanced';
  improvement_range: [number, number];
  difficulty: 'easy' | 'medium' | 'hard';
  implementation_time: string;
  requirements: string[];
  preview_available: boolean;
}

interface GeneratedOptimization {
  id: string;
  html_code: string;
  css_code: string;
  js_code: string;
  implementation_notes: string[];
  expected_performance: {
    rpm_improvement: number;
    ctr_improvement: number;
    revenue_increase: number;
    confidence_score: number;
  };
  optimization_types: string[];
  estimated_impact: 'low' | 'medium' | 'high' | 'critical';
  deployment_instructions: {
    steps: string[];
    testing_checklist: string[];
    rollback_plan: string[];
  };
  monitoring_setup: {
    metrics_to_track: string[];
    alert_conditions: string[];
    reporting_frequency: string;
  };
}

interface OptimizationTask {
  id?: string;
  site_id: string;
  client_id: string;
  task_type: string;
  config_data: any;
  status: 'pending' | 'processing' | 'completed' | 'failed';
  expected_improvement: number;
  created_at?: string;
  updated_at?: string;
}

// === ANIMATION KEYFRAMES ENTERPRISE ===
const matrixEffect = keyframes`
  0% { transform: translateY(-100%); opacity: 0; }
  50% { opacity: 1; }
  100% { transform: translateY(100vh); opacity: 0; }
`;

const codeGeneration = keyframes`
  0% { width: 0%; opacity: 0; }
  50% { opacity: 1; }
  100% { width: 100%; opacity: 1; }
`;

const optimizationPulse = keyframes`
  0%, 100% { box-shadow: 0 0 0 0 rgba(48, 209, 88, 0.4); }
  50% { box-shadow: 0 0 0 20px rgba(48, 209, 88, 0); }
`;

const performanceBoost = keyframes`
  0% { transform: scale(1) rotate(0deg); }
  25% { transform: scale(1.05) rotate(5deg); }
  50% { transform: scale(1.1) rotate(0deg); }
  75% { transform: scale(1.05) rotate(-5deg); }
  100% { transform: scale(1) rotate(0deg); }
`;

